function extractQuestion(text) {
  const t = String(text || '').trim();
  if (!t) return [];
  const parts = t.split(/[?？]/).map((s) => s.trim()).filter(Boolean);
  if (parts.length > 1) {
    return parts.slice(0, -1).map((p) => `${p}?`.slice(0, 300)).slice(0, 3);
  }
  if (/[?？]/.test(t)) return [t.slice(0, 300)];
  return [];
}

function buildIntakeStubFromRow(row) {
  const text = String(row.text || '').trim();
  const segment = String(row.segment || 'general_inbound').trim().toLowerCase();
  const score = Number(row.score || 0);
  const platform = String(row.platform || 'tiktok').trim().toLowerCase();
  const questions = extractQuestion(text);
  const summary = text.slice(0, 500);

  return {
    intake_version: 1,
    verdict: score >= 70 ? 'qualified' : score >= 40 ? 'maybe' : 'reject',
    score,
    reject_reason: null,
    summary,
    conversation: {
      surface_topic: summary.slice(0, 200),
      explicit_questions: questions.length ? questions : [summary.slice(0, 120)],
      implicit_fears: [],
      misconceptions: [],
      journey_stage: 'consideration',
      audience_voice: text.slice(0, 300),
    },
    content_signals: {
      pain_intensity: Math.min(100, Math.max(0, score)),
      discussion_heat: score >= 75 ? 'high' : 'medium',
      inbound_potential: score >= 70 ? 'medium' : 'low',
      segment_hint: segment,
      evidence_quotes: text ? [text.slice(0, 120)] : [],
      single_insight_clip: true,
      hook_candidate: text.slice(0, 80),
      cta_keyword_hint: segment === 'noxh_income' ? 'NOXH' : 'CHECKLIST',
    },
    compliance_flags: [],
    _stub: true,
    _stub_source: String(row.intake_stub_source || row.source || 'classified_row'),
    _stub_platform: platform,
    _stub_normalized_key: String(row.normalized_key || ''),
  };
}

function ensureIntakeV1(row, meta) {
  if (meta?.intake_v1 && typeof meta.intake_v1 === 'object') {
    return { meta, intake_v1: meta.intake_v1, stubbed: false };
  }
  const intake_v1 = buildIntakeStubFromRow(row);
  const next = { ...meta, intake_v1, intake_stub_at: new Date().toISOString() };
  return { meta: next, intake_v1, stubbed: true };
}

const MIN_SCORE = 70;
const BATCH = 5;

const ALLOW_SEGMENTS = new Set([
  'noxh_income', 'valuation', 'sme_credit', 'general_inbound',
]);

function parseMeta(raw) {
  if (!raw) return {};
  try {
    return typeof raw === 'string' ? JSON.parse(raw) : raw;
  } catch {
    return {};
  }
}

const res = $input.first().json;
const rows = Array.isArray(res.values) ? res.values : [];
if (rows.length < 2) {
  return [{ json: { empty: true, message: 'content_queue trống' } }];
}

const headers = rows[0].map((x) => String(x ?? '').trim().toLowerCase());
const out = [];

for (let i = 1; i < rows.length; i += 1) {
  const cells = rows[i];
  if (!cells?.some((c) => String(c ?? '').trim())) continue;

  const row = { sheet_row: i + 1 };
  headers.forEach((key, j) => {
    if (key) row[key] = cells[j] ?? '';
  });

  const meta = parseMeta(row.meta);
  if (meta.editorial_brief_v1) continue;

  const segment = String(row.segment || '').trim().toLowerCase();
  const score = Number(row.score || 0);
  const status = String(row.status || '').trim().toLowerCase();
  const verdict = String(row.claude_verdict || '').trim().toLowerCase();

  if (score < MIN_SCORE) continue;
  if (!ALLOW_SEGMENTS.has(segment)) continue;
  if (status !== 'classified' && verdict !== 'qualified') continue;

  const text = String(row.text || '').trim();
  if (text.length < 20) continue;

  const ensured = ensureIntakeV1(
    { ...row, segment, score, intake_stub_source: 'layer_b_filter' },
    meta
  );

  row.meta_parsed = ensured.meta;
  row.intake_v1 = ensured.intake_v1;
  row.intake_stubbed = ensured.stubbed;
  out.push({ json: row });
  if (out.length >= BATCH) break;
}

if (!out.length) {
  return [{
    json: {
      empty: true,
      message: 'Không còn dòng cần editorial brief (classified score≥70 + chưa editorial_brief_v1)',
    },
  }];
}

return out;

const data = $getWorkflowStaticData('global');
data.eb_stats = { brief_ok: 0, brief_fail: 0, parse_fail: 0, llm_fail: 0, no_candidates: false, sheet_fail: 0 };
return $input.all();

/** Segments that must have legal_retrieval_pack before content production */
const SEGMENTS_REQUIRING_LEGAL_KB = new Set([
  'noxh_income',
  'valuation',
  'sme_credit',
]);

/** Magnix classify segment → legal-sources topic */
const SEGMENT_TO_LEGAL_TOPIC = {
  noxh_income: 'noxh_income',
  valuation: 'valuation_certificate',
  sme_credit: 'loan_dti',
};

const DEFAULT_FORBIDDEN = [
  'Cam kết duyệt',
  'Chắc chắn mua được',
  'Lãi suất cố định áp dụng cho tất cả',
  '100% thành công',
];

function segmentRequiresLegalKb(segment) {
  return SEGMENTS_REQUIRING_LEGAL_KB.has(String(segment || '').trim().toLowerCase());
}

function segmentToLegalTopic(segment) {
  const key = String(segment || '').trim().toLowerCase();
  return SEGMENT_TO_LEGAL_TOPIC[key] || null;
}

function detectProvinceFromText(text) {
  const t = String(text || '').toLowerCase().normalize('NFD').replace(/\p{M}/gu, '');
  const aliases = {
    tp_ho_chi_minh: ['tp hcm', 'hcm', 'ho chi minh', 'tphcm', 'sai gon'],
    dong_nai: ['dong nai', 'bien hoa'],
    binh_duong: ['binh duong', 'thu dau mot'],
    ba_ria_vung_tau: ['vung tau', 'ba ria'],
    tp_can_tho: ['can tho'],
  };
  for (const [code, list] of Object.entries(aliases)) {
    for (const a of list) {
      if (t.includes(a.normalize('NFD').replace(/\p{M}/gu, ''))) return code;
    }
  }
  return null;
}


const LEGAL_PACK_BUNDLE = __LEGAL_PACK_BUNDLE_JSON__;

function resolvePackFromBundle(segment, text) {
  const topic = segmentToLegalTopic(segment);
  if (!topic) return null;

  const bySegment = LEGAL_PACK_BUNDLE.packs_by_segment || {};
  const byTopic = LEGAL_PACK_BUNDLE.packs_by_topic || {};
  let pack = bySegment[segment] || byTopic[topic];
  if (!pack) return null;

  const province = detectProvinceFromText(text);
  if (province && Array.isArray(LEGAL_PACK_BUNDLE.packs_by_topic)) {
    // no-op: province-specific packs use topic_local keys when present
  }
  const localKey = province ? `${topic}__${province}` : null;
  if (localKey && byTopic[localKey]) {
    pack = byTopic[localKey];
  }

  return JSON.parse(JSON.stringify(pack));
}

function assessLegalGate(segment, pack) {
  const required = segmentRequiresLegalKb(segment);
  if (!required) {
    return { required: false, pass: true, block_reason: null };
  }
  if (!pack) {
    return {
      required: true,
      pass: false,
      block_reason: 'MISSING_LEGAL_PACK',
      needs_human_legal_source: true,
    };
  }
  if (pack.needs_human_legal_source === true) {
    return {
      required: true,
      pass: false,
      block_reason: 'NEEDS_HUMAN_LEGAL_SOURCE',
      needs_human_legal_source: true,
    };
  }
  if (!Array.isArray(pack.facts) || pack.facts.length === 0) {
    return {
      required: true,
      pass: false,
      block_reason: 'EMPTY_LEGAL_FACTS',
      needs_human_legal_source: true,
    };
  }
  return {
    required: true,
    pass: true,
    block_reason: null,
    needs_human_legal_source: false,
    fact_count: pack.facts.length,
  };
}

function buildMinimalBlockedPack(segment, reason) {
  return {
    topic: segmentToLegalTopic(segment) || 'unknown',
    intent: 'short_legal_explainer',
    facts: [],
    forbidden_claims: DEFAULT_FORBIDDEN,
    disclaimer_required: true,
    needs_human_legal_source: true,
    block_reason: reason,
  };
}


const row = $('Loop Brief Candidates').item?.json || $input.first().json;
const segment = String(row.segment || '').trim().toLowerCase();
const text = String(row.text || '');

if (!segmentRequiresLegalKb(segment)) {
  return [{
    json: {
      ...row,
      legal_gate: { required: false, pass: true },
      legal_retrieval_pack: null,
    },
  }];
}

let pack = resolvePackFromBundle(segment, text);
const gate = assessLegalGate(segment, pack);

if (!pack && !gate.pass) {
  pack = buildMinimalBlockedPack(segment, gate.block_reason);
}

return [{
  json: {
    ...row,
    legal_retrieval_pack: pack,
    legal_gate: gate,
    legal_topic: segmentToLegalTopic(segment),
  },
}];

const row = $('Loop Brief Candidates').item?.json || $input.first().json;

const system = `Bạn là **Magnix Editorial Strategist** — biên tập inbound BĐS/tài chính VN, Value-First Hook, không hard sell.

**[/silent]** suy luận nội bộ. Output **chỉ JSON hợp lệ**.

## Input bạn nhận

- \`intake_v1\` — pain intake đã parse (câu hỏi, fears, quotes…)
- \`segment\`, \`platform\`, \`score\`, \`text\` gốc (reference)
- (optional) \`pattern_refs\` — hook/pattern từ scorecard (có thể rỗng)
- **\`legal_retrieval_pack\`** — khi \`requires_legal_kb: true\`: facts, forbidden_claims, disclaimer (bắt buộc tuân)

## Nhiệm vụ

1. Chọn **một góc editorial** duy nhất (một clip = một insight).
2. Xây \`qa_backbone\` — 2–4 cặp Q&A (câu hỏi search + góc trả lời, không hứa lãi/duyệt chắc).
3. Đề xuất \`recommended_formats\` (video_30s ưu tiên nếu platform video).
4. \`deconstruct_rules\` — không copy đối thủ, compliance Magnix.
5. \`editorial_title\` — tiêu đề nội bộ ≤80 ký tự.
6. Nếu có \`legal_retrieval_pack\`: mỗi \`answer_angle\` khớp fact trong pack; \`source_refs\` = \`claim_id\`.

## Quy tắc Q&A

- Mỗi \`question\` phải bắt nguồn từ \`explicit_questions\` hoặc pain trong intake.
- Mỗi \`answer_angle\` = **góc trả lời** (reframe, checklist, DTI…) — không phải script đọc.
- \`search_keyword\` — từ khóa pain cho SEO/Shorts (tiếng Việt, tự nhiên).

## Platform

| platform | format ưu tiên |
|----------|----------------|
| tiktok, fb_reels, youtube_shorts | video_30s priority 1 |
| fb_page | carousel hoặc video_45s |`;

function normPlatform(raw) {
  const key = String(raw || 'tiktok').trim().toLowerCase();
  const map = {
    tt: 'tiktok',
    fb: 'fb_reels',
    fb_group: 'fb_reels',
    fb_page: 'fb_reels',
    reels: 'fb_reels',
    shorts: 'youtube_shorts',
  };
  return map[key] || key;
}

const legalPack = row.legal_retrieval_pack || null;
const legalGate = row.legal_gate || { required: false, pass: true };

const userPayload = JSON.stringify({
  normalized_key: row.normalized_key,
  platform: row.platform,
  target_platform: normPlatform(row.platform),
  segment: row.segment,
  score: Number(row.score || 0),
  text: String(row.text || '').slice(0, 8000),
  intake_v1: row.intake_v1 || row.meta_parsed?.intake_v1,
  pattern_refs: row.meta_parsed?.pattern_refs || [],
  legal_retrieval_pack: legalPack,
  legal_gate: legalGate,
  requires_legal_kb: legalGate.required === true,
});

try {
  if ($env.DEEPSEEK_API_KEY) {
    const res = await this.helpers.httpRequest({
      method: 'POST',
      url: $env.DEEPSEEK_API_URL || 'https://api.deepseek.com/chat/completions',
      headers: {
        Authorization: `Bearer ${$env.DEEPSEEK_API_KEY}`,
        'Content-Type': 'application/json',
      },
      body: {
        model: $env.DEEPSEEK_MODEL || 'deepseek-chat',
        temperature: 0.35,
        max_tokens: 4096,
        response_format: { type: 'json_object' },
        messages: [
          { role: 'system', content: system },
          { role: 'user', content: userPayload },
        ],
      },
